INSERT INTO `occasions` VALUES (1,'Diwali','Festival','Pan-India','Festival of lights, grand traditional wear like silks and embroidered ethnic outfits','ΓÇó Mojaris or jutis, silk pocket square, gold/silver kada, turban for special events, stole','ΓÇó Royal: Maroon, deep red, gold, cream, navy blue\nΓÇó Festive: Orange, yellow, emerald green\nΓÇó Metallic accents: Gold, copper threading','Γ£à DO: Rich fabrics, vibrant colors, iron well\nΓ¥î DON\'T: All black, overly casual, skip accessories','Male','ΓÇó Traditional: Silk kurta with churidar, embroidered Nehru jacket, sherwani\nΓÇó Modern: Designer kurta with slim trousers, bandi jacket\nΓÇó Fabric: Silk, brocade, cotton silk'),(2,'Holi','Festival','Pan-India','Festival of colors, comfortable white cottons or light breathable fabrics','ΓÇó Sunglasses (protect from colors), minimal jewelry, kolhapuri chappals, waterproof watch','ΓÇó Base: White or light pastels\nΓÇó After play: Rainbow colors!\nΓÇó Tip: Old comfortable clothes','Γ£à DO: White/light colors, oil on skin before play, comfortable footwear\nΓ¥î DON\'T: Expensive clothes, silk, heavy jewelry','Male','ΓÇó Casual: White kurta with pajama or churidar\nΓÇó Modern: White t-shirt with white chinos\nΓÇó Fabric: Cotton, khadi (easy to wash)'),(3,'Eid al-Fitr','Festival','Pan-India','Celebratory traditional wear, elegant embroidery and festive ethnic wear','ΓÇó Traditional cap (topi), elegant mojaris, pocket square, attar perfume, prayer beads','ΓÇó Classic: White, cream, light gold, mint green\nΓÇó Festive: Powder blue, rose, lavender\nΓÇó Avoid: Very dark colors','Γ£à DO: Fresh clean clothes, modest style, traditional footwear\nΓ¥î DON\'T: Flashy jewelry, shorts, western casuals','Male','ΓÇó Traditional: Kurta with pajama, sherwani with churidar\nΓÇó Modern: Pathani suit, Lucknowi kurta\nΓÇó Fabric: Cotton, silk, linen blend'),(4,'Navratri (Garba Night)','Festival','Gujarat','High-energy dance event, colorful traditional Gujarati attire','ΓÇó Colorful pagdi (turb